const ACCENT = "#B8896A";
const INK = "#1C1C1C";
const IVORY = "#FAF8F5";
const MUTED = "#888888";

function SpeciesCard({ species, phylumNum, className, onClose }) {
  const [name, flag, note] = species;
  const colors = PHYLUM_COLORS[phylumNum];
  const isSensitive = flag === "S";
  const isCrossover = flag === "X";
  return (
    <div onClick={onClose} style={{ position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:"1rem" }}>
      <div onClick={e => e.stopPropagation()} style={{ background:IVORY,borderRadius:"12px",padding:"2rem",maxWidth:"500px",width:"100%",maxHeight:"80vh",overflowY:"auto",boxShadow:"0 20px 60px rgba(0,0,0,0.3)" }}>
        <div style={{ display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:"1rem" }}>
          <div>
            <div style={{ fontSize:"0.7rem",color:ACCENT,textTransform:"uppercase",letterSpacing:"0.1em",marginBottom:"0.25rem",fontFamily:"serif" }}>Species · Phylum {phylumNum}</div>
            <h2 style={{ fontFamily:"Georgia,serif",fontSize:"1.4rem",color:INK,margin:0 }}>{name}</h2>
          </div>
          <button onClick={onClose} style={{ background:"none",border:"none",fontSize:"1.5rem",cursor:"pointer",color:MUTED,lineHeight:1 }}>×</button>
        </div>
        <div style={{ display:"flex",gap:"0.5rem",flexWrap:"wrap",marginBottom:"1rem" }}>
          <span style={{ background:colors.bg,color:colors.accent,padding:"0.2rem 0.6rem",borderRadius:"20px",fontSize:"0.7rem",fontFamily:"serif" }}>Phylum {phylumNum}</span>
          <span style={{ background:"#f0ece6",color:MUTED,padding:"0.2rem 0.6rem",borderRadius:"20px",fontSize:"0.7rem",fontFamily:"serif" }}>{className}</span>
          {isSensitive && <span style={{ background:"#FFF0F0",color:"#C0392B",padding:"0.2rem 0.6rem",borderRadius:"20px",fontSize:"0.7rem",fontFamily:"serif",fontWeight:"bold" }}>⚠ SENSITIVE</span>}
          {isCrossover && <span style={{ background:"#F0F0F0",color:MUTED,padding:"0.2rem 0.6rem",borderRadius:"20px",fontSize:"0.7rem",fontFamily:"serif" }}>◆ CROSSOVER</span>}
        </div>
        <div style={{ background:"#f5f0ea",padding:"1rem",borderRadius:"8px",borderLeft:"3px solid " + (isSensitive ? "#C0392B" : ACCENT) }}>
          <div style={{ fontSize:"0.7rem",color:ACCENT,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:"0.4rem",fontFamily:"serif" }}>Field Note</div>
          <p style={{ fontFamily:"Georgia,serif",fontSize:"0.9rem",color:INK,margin:0,lineHeight:1.6,fontStyle:"italic" }}>
            {note || "Full species entry — era of origin, defining characteristics, key garments, and natural habitat — forthcoming in the expanded edition."}
          </p>
        </div>
      </div>
    </div>
  );
}

function PhylumView({ phylum, onSpeciesClick }) {
  const [activeClass, setActiveClass] = useState(null);
  const colors = PHYLUM_COLORS[phylum.number];
  const displayClasses = activeClass === null ? phylum.classes : phylum.classes.filter(c => c.name === activeClass);
  return (
    <div>
      <div style={{ marginBottom:"1.5rem",display:"flex",flexWrap:"wrap",gap:"0.4rem" }}>
        <button onClick={() => setActiveClass(null)} style={{ padding:"0.3rem 0.7rem",borderRadius:"20px",border:"none",background:activeClass===null?colors.bg:"#f0ece6",color:activeClass===null?colors.accent:MUTED,cursor:"pointer",fontSize:"0.7rem",fontFamily:"serif" }}>All</button>
        {phylum.classes.map(c => (
          <button key={c.name} onClick={() => setActiveClass(activeClass===c.name?null:c.name)} style={{ padding:"0.3rem 0.7rem",borderRadius:"20px",border:"none",background:activeClass===c.name?colors.bg:"#f0ece6",color:activeClass===c.name?colors.accent:MUTED,cursor:"pointer",fontSize:"0.7rem",fontFamily:"serif" }}>{c.name}</button>
        ))}
      </div>
      {displayClasses.map(cls => (
        <div key={cls.name} style={{ marginBottom:"1.5rem" }}>
          <div style={{ background:INK,color:"white",padding:"0.5rem 1rem",borderRadius:"6px",fontSize:"0.8rem",fontFamily:"serif",letterSpacing:"0.05em",marginBottom:"0.75rem",borderLeft:"4px solid "+colors.accent }}>{cls.name}</div>
          <div style={{ display:"flex",flexWrap:"wrap",gap:"0.4rem" }}>
            {cls.species.map(s => {
              const [sname, sflag] = s;
              const isS = sflag==="S", isX = sflag==="X";
              return (
                <button key={sname} onClick={() => onSpeciesClick(s, phylum.number, cls.name)}
                  style={{ padding:"0.3rem 0.7rem",borderRadius:"20px",border:"1px solid "+(isS?"#C0392B":isX?"#ccc":"#e0d8d0"),background:isS?"#FFF8F8":isX?"#F8F8F8":IVORY,color:isS?"#C0392B":isX?MUTED:INK,cursor:"pointer",fontSize:"0.8rem",fontFamily:"Georgia,serif",transition:"all 0.15s" }}
                  onMouseEnter={e=>{e.target.style.background=colors.bg;e.target.style.color=colors.accent;e.target.style.borderColor=colors.accent;}}
                  onMouseLeave={e=>{e.target.style.background=isS?"#FFF8F8":isX?"#F8F8F8":IVORY;e.target.style.color=isS?"#C0392B":isX?MUTED:INK;e.target.style.borderColor=isS?"#C0392B":isX?"#ccc":"#e0d8d0";}}
                >{isS&&"⚠ "}{sname}{isX&&" ◆"}</button>
              );
            })}
          </div>
        </div>
      ))}
    </div>
  );
}

function SearchView({ query, onSpeciesClick }) {
  const results = useMemo(() => {
    if (!query || query.length < 2) return [];
    const q = query.toLowerCase();
    const matches = [];
    for (const p of ATLAS_DATA.phyla) {
      for (const c of p.classes) {
        for (const s of c.species) {
          if (s[0].toLowerCase().includes(q) || s[2].toLowerCase().includes(q)) {
            matches.push({ species:s, phylumNum:p.number, phylumName:p.name, className:c.name });
            if (matches.length >= 80) return matches;
          }
        }
      }
    }
    return matches;
  }, [query]);
  if (!query || query.length < 2) return <div style={{ textAlign:"center",padding:"4rem",color:MUTED,fontFamily:"Georgia,serif",fontStyle:"italic" }}>Type to search all 2,926 species…</div>;
  return (
    <div>
      <div style={{ marginBottom:"1rem",color:MUTED,fontFamily:"serif",fontSize:"0.85rem" }}>{results.length === 80 ? "80+ results" : results.length+" results"} for "{query}"</div>
      <div style={{ display:"flex",flexDirection:"column",gap:"0.4rem" }}>
        {results.map(({ species, phylumNum, phylumName, className }) => {
          const colors = PHYLUM_COLORS[phylumNum];
          return (
            <button key={phylumNum+"-"+species[0]} onClick={() => onSpeciesClick(species, phylumNum, className)}
              style={{ display:"flex",alignItems:"center",gap:"0.75rem",padding:"0.6rem 0.75rem",borderRadius:"8px",border:"1px solid #e0d8d0",background:IVORY,cursor:"pointer",textAlign:"left",transition:"all 0.15s" }}
              onMouseEnter={e=>{e.currentTarget.style.background="#f5f0ea";e.currentTarget.style.borderColor=ACCENT;}}
              onMouseLeave={e=>{e.currentTarget.style.background=IVORY;e.currentTarget.style.borderColor="#e0d8d0";}}>
              <span style={{ background:colors.bg,color:colors.accent,padding:"0.15rem 0.5rem",borderRadius:"20px",fontSize:"0.65rem",fontFamily:"serif",whiteSpace:"nowrap" }}>P{phylumNum}</span>
              <span style={{ fontFamily:"Georgia,serif",fontSize:"0.9rem",color:INK,flex:1 }}>{species[0]}</span>
              <span style={{ fontSize:"0.7rem",color:MUTED,fontFamily:"serif",maxWidth:"160px",textAlign:"right" }}>{className}</span>
              {species[1]==="S" && <span style={{ color:"#C0392B",fontSize:"0.7rem" }}>⚠</span>}
              {species[1]==="X" && <span style={{ color:MUTED,fontSize:"0.7rem" }}>◆</span>}
            </button>
          );
        })}
      </div>
    </div>
  );
}

function StatsView() {
  const counts = useMemo(() => {
    let s=0, x=0;
    for (const p of ATLAS_DATA.phyla) for (const c of p.classes) for (const sp of c.species) { if(sp[1]==="S") s++; else if(sp[1]==="X") x++; }
    return {s, x};
  }, []);
  return (
    <div>
      <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fit, minmax(150px,1fr))",gap:"1rem",marginBottom:"2rem" }}>
        {[["2,926","Total Species",ACCENT],[12,"Phyla","#7B68EE"],[155,"Classes","#52B788"],[counts.s,"Sensitive","#C0392B"],[counts.x,"Crossover",MUTED]].map(([v,l,c]) => (
          <div key={l} style={{ background:IVORY,border:"1px solid #e0d8d0",borderTop:"3px solid "+c,borderRadius:"10px",padding:"1.25rem" }}>
            <div style={{ fontFamily:"Georgia,serif",fontSize:"1.8rem",fontWeight:"bold",color:c,lineHeight:1.1,marginBottom:"0.4rem" }}>{v}</div>
            <div style={{ fontFamily:"serif",fontSize:"0.7rem",color:MUTED,textTransform:"uppercase",letterSpacing:"0.08em" }}>{l}</div>
          </div>
        ))}
      </div>
      <h3 style={{ fontFamily:"Georgia,serif",color:INK,marginBottom:"1rem",fontSize:"1rem" }}>Distribution by Phylum</h3>
      {ATLAS_DATA.phyla.map(p => {
        const colors = PHYLUM_COLORS[p.number];
        const pct = (p.count / 2926 * 100).toFixed(1);
        return (
          <div key={p.number} style={{ marginBottom:"0.6rem" }}>
            <div style={{ display:"flex",justifyContent:"space-between",marginBottom:"0.2rem" }}>
              <span style={{ fontFamily:"serif",fontSize:"0.8rem",color:INK }}>{p.emoji} {p.name}</span>
              <span style={{ fontFamily:"serif",fontSize:"0.8rem",color:MUTED }}>{p.count}</span>
            </div>
            <div style={{ background:"#e8e0d8",borderRadius:"4px",height:"6px",overflow:"hidden" }}>
              <div style={{ background:colors.accent,height:"100%",width:pct+"%",borderRadius:"4px" }} />
            </div>
          </div>
        );
      })}
    </div>
  );
}

export default function App() {
  const [view, setView] = useState("home");
  const [activePhylum, setActivePhylum] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedSpecies, setSelectedSpecies] = useState(null);
  const [selectedPhylumNum, setSelectedPhylumNum] = useState(null);
  const [selectedClassName, setSelectedClassName] = useState("");

  const handleSpeciesClick = useCallback((species, phylumNum, className) => {
    setSelectedSpecies(species); setSelectedPhylumNum(phylumNum); setSelectedClassName(className);
  }, []);

  const currentPhylum = activePhylum !== null ? ATLAS_DATA.phyla.find(p => p.number === activePhylum) : null;

  return (
    <div style={{ background:IVORY,minHeight:"100vh" }}>
      <div style={{ background:INK,padding:"0.75rem 1.5rem",display:"flex",alignItems:"center",gap:"1rem",position:"sticky",top:0,zIndex:100,boxShadow:"0 2px 8px rgba(0,0,0,0.3)" }}>
        <button onClick={() => { setView("home"); setActivePhylum(null); setSearchQuery(""); }} style={{ background:"none",border:"none",cursor:"pointer",padding:0,flexShrink:0 }}>
          <span style={{ fontFamily:"Georgia,serif",fontSize:"1rem",fontWeight:"bold",color:IVORY }}>Atlas of</span>
          <span style={{ fontFamily:"Georgia,serif",fontSize:"1rem",fontWeight:"bold",color:ACCENT }}> Fashion Aesthetics</span>
        </button>
        <input placeholder="Search 2,926 species…" value={searchQuery}
          onChange={e => { setSearchQuery(e.target.value); if(e.target.value.length>1) setView("search"); else if(!e.target.value) setView(activePhylum?"phylum":"home"); }}
          style={{ flex:1,padding:"0.4rem 0.8rem",borderRadius:"20px",border:"1px solid #444",background:"#2a2a2a",color:IVORY,fontFamily:"Georgia,serif",fontSize:"0.85rem",outline:"none" }}
        />
        <button onClick={() => setView("stats")} style={{ background:view==="stats"?ACCENT:"transparent",border:"1px solid "+(view==="stats"?ACCENT:"#444"),color:view==="stats"?INK:"#999",padding:"0.3rem 0.6rem",borderRadius:"6px",cursor:"pointer",fontSize:"0.8rem",flexShrink:0 }}>📊</button>
      </div>

      <div style={{ maxWidth:"900px",margin:"0 auto",padding:"1.5rem" }}>
        {view === "home" && (
          <div>
            <div style={{ textAlign:"center",padding:"2rem 0 2.5rem",borderBottom:"1px solid "+ACCENT,marginBottom:"2rem" }}>
              <div style={{ fontFamily:"serif",fontSize:"0.8rem",color:ACCENT,letterSpacing:"0.2em",textTransform:"uppercase",marginBottom:"0.5rem" }}>Kingdom · Fashion Aesthetic Culture</div>
              <h1 style={{ fontFamily:"Georgia,serif",fontSize:"2.2rem",color:INK,margin:"0 0 0.5rem",lineHeight:1.2 }}>Atlas of Fashion Aesthetics</h1>
              <p style={{ color:MUTED,fontFamily:"Georgia,serif",fontStyle:"italic",margin:"0 0 0.75rem",fontSize:"0.9rem" }}>2,926 Species · 12 Phyla · 155 Classes · 2026 Edition</p>
              <p style={{ color:INK,fontFamily:"Georgia,serif",fontSize:"0.85rem",maxWidth:"480px",margin:"0 auto",lineHeight:1.7,opacity:0.8 }}>Organised by origin engine, not visual appearance. Click any phylum to browse. Search to find any species instantly.</p>
            </div>
            <div style={{ display:"grid",gridTemplateColumns:"repeat(auto-fill, minmax(195px,1fr))",gap:"0.75rem" }}>
              {ATLAS_DATA.phyla.map(p => {
                const colors = PHYLUM_COLORS[p.number];
                return (
                  <button key={p.number} onClick={() => { setActivePhylum(p.number); setView("phylum"); }}
                    style={{ background:IVORY,border:"1px solid #e0d8d0",borderTop:"3px solid "+colors.accent,borderRadius:"10px",padding:"1.25rem",cursor:"pointer",textAlign:"left",transition:"all 0.2s" }}
                    onMouseEnter={e=>{const el=e.currentTarget;el.style.background=colors.bg;el.style.borderColor=colors.accent;el.querySelectorAll(".pn,.pd").forEach((x,i)=>{x.style.color=i===0?colors.accent:"#aaa";});}}
                    onMouseLeave={e=>{const el=e.currentTarget;el.style.background=IVORY;el.style.borderColor="#e0d8d0";el.querySelectorAll(".pn,.pd").forEach((x,i)=>{x.style.color=i===0?INK:MUTED;});}}>
                    <div style={{ fontSize:"1.4rem",marginBottom:"0.4rem" }}>{p.emoji}</div>
                    <div style={{ fontSize:"0.6rem",color:ACCENT,fontFamily:"serif",letterSpacing:"0.1em",marginBottom:"0.2rem" }}>PHYLUM {p.number}</div>
                    <div className="pn" style={{ fontFamily:"Georgia,serif",fontSize:"0.95rem",fontWeight:"bold",color:INK,marginBottom:"0.25rem",transition:"color 0.2s" }}>{p.name}</div>
                    <div className="pd" style={{ fontFamily:"serif",fontSize:"0.7rem",color:MUTED,lineHeight:1.4,marginBottom:"0.5rem",transition:"color 0.2s" }}>{p.description}</div>
                    <div style={{ fontFamily:"serif",fontSize:"0.7rem",color:colors.accent }}>{p.count} species · {p.classes.length} classes</div>
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {view === "phylum" && currentPhylum && (
          <div>
            <button onClick={() => { setView("home"); setActivePhylum(null); }} style={{ background:"none",border:"none",color:ACCENT,cursor:"pointer",fontFamily:"serif",fontSize:"0.85rem",padding:0,marginBottom:"1rem" }}>← All Phyla</button>
            <div style={{ display:"flex",alignItems:"center",gap:"0.75rem",marginBottom:"1.5rem" }}>
              <span style={{ fontSize:"2rem" }}>{currentPhylum.emoji}</span>
              <div>
                <div style={{ fontSize:"0.65rem",color:ACCENT,fontFamily:"serif",letterSpacing:"0.12em",textTransform:"uppercase" }}>Phylum {currentPhylum.number}</div>
                <h2 style={{ fontFamily:"Georgia,serif",fontSize:"1.8rem",color:INK,margin:"0 0 0.2rem" }}>{currentPhylum.name}</h2>
                <div style={{ color:MUTED,fontFamily:"serif",fontSize:"0.8rem" }}>{currentPhylum.description} · {currentPhylum.count} species</div>
              </div>
            </div>
            <PhylumView phylum={currentPhylum} onSpeciesClick={handleSpeciesClick} />
          </div>
        )}

        {view === "search" && <SearchView query={searchQuery} onSpeciesClick={handleSpeciesClick} />}
        {view === "stats" && (
          <div>
            <h2 style={{ fontFamily:"Georgia,serif",fontSize:"1.5rem",color:INK,marginBottom:"1.5rem",paddingBottom:"0.75rem",borderBottom:"1px solid "+ACCENT }}>Atlas Statistics · 2026 Edition</h2>
            <StatsView />
          </div>
        )}
      </div>

      {selectedSpecies && <SpeciesCard species={selectedSpecies} phylumNum={selectedPhylumNum} className={selectedClassName} onClose={() => setSelectedSpecies(null)} />}
    </div>
  );
}
